targets.parsedQuery:
db.artifactJobs.aggregate([
  {
    "$match": {
      "createdAt": {
        "$gte": "$__timeFrom",
        "$lte": "$__timeTo"
      }
    }
  },

  {
    "$addFields": {
      "__passesTypeFilter": {
        "$or": [
          {"$eq": ["$_artifact_type", "all"]},
          {"$eq": [{"$toString": "$artifactTypeId"}, "$_artifact_type"]}
        ]
      }
    }
  },
  {
    "$match": {"__passesTypeFilter": true}
  },
  {
    "$group": {
      "_id": "$artifactTypeId",
      "count": {
        "$sum": 1
      }
    }
  },
  {
    "$sort": {
      "count": -1
    }
  },
  {
    "$limit": 15
  },
  {
    "$project": {
      "artifactType": {
        "$switch": {
          "branches": [
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "68ff690c848c3eae6510ab02"
                ]
              },
              "then": "Colorized Master Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "680768f31ef32e607151e4b0"
                ]
              },
              "then": "Normalized Master Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "68e66f1ed394af72c52e0f07"
                ]
              },
              "then": "Full Product Feature Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "68c80874c49b0cf616cabc01"
                ]
              },
              "then": "Feature Focus Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "67ebf0a2c98256999f900fe6"
                ]
              },
              "then": "Gallery"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "67e3108d7fa4577d5789087a"
                ]
              },
              "then": "Product 360 Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "68e302de1dd85ffb3bfa51cf"
                ]
              },
              "then": "Fast Closeup Sequence Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "68752762df6a45a8e6c4e91d"
                ]
              },
              "then": "Intro to 360 Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "68062eb2682737ec93ac6350"
                ]
              },
              "then": "Dimensions Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "6808cbfefd01c05a31cea41c"
                ]
              },
              "then": "Action Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "68e6047030e7001c4d62baea"
                ]
              },
              "then": "Ingredients Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "68dff14630e7001c4d62bae7"
                ]
              },
              "then": "Unbox Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "68e603ea30e7001c4d62bae9"
                ]
              },
              "then": "Badge Overlay Video"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "6857a0f0d0b1c2a3e4f56789"
                ]
              },
              "then": "Update Capture Request Status"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "6465c12fc5433625ec7f491b"
                ]
              },
              "then": "Suggest Color Correction"
            },
            {
              "case": {
                "$eq": [
                  {
                    "$toString": "$_id"
                  },
                  "6825cf5470d379f31cef9423"
                ]
              },
              "then": "Set Shots Color Correction"
            }
          ],
          "default": {
            "$toString": "$_id"
          }
        }
      },
      "value": "$count",
      "_id": 0
    }
  }
])

